import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormGroup, FormControl, ReactiveFormsModule } from '@angular/forms';
import { AdminSetting } from '../../core/models';

interface ServiceGroup {
  service: string;
  label: string;
  settings: AdminSetting[];
  configured: boolean;
}

@Component({
  selector: 'app-admin-settings',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './admin-settings.component.html',
  styleUrl: './admin-settings.component.css',
})
export class AdminSettingsComponent {
  /** Which service (if any) is currently saving. */
  readonly savingService = signal<string>('');

  /** Human-friendly service names. */
  private readonly serviceLabels: Record<string, string> = {
    postgresql: 'PostgreSQL',
    minio: 'MinIO Object Storage',
  };

  readonly settings = signal<AdminSetting[]>([
    { key: 'DATABASE_URL', service: 'postgresql', label: 'Database URL', value: 'postgres://***', configured: true },
    { key: 'MINIO_ENDPOINT', service: 'minio', label: 'Endpoint', value: '', configured: false },
    { key: 'MINIO_ACCESS_KEY', service: 'minio', label: 'Access Key', value: '', configured: false },
    { key: 'MINIO_SECRET_KEY', service: 'minio', label: 'Secret Key', value: '', configured: false },
  ]);

  /** Reactive form: one control per setting key. */
  readonly form = new FormGroup<Record<string, FormControl<string>>>({});

  /** Settings grouped by service for rendering. */
  readonly groups = computed<ServiceGroup[]>(() => {
    const bySvc = new Map<string, AdminSetting[]>();
    for (const s of this.settings()) {
      const list = bySvc.get(s.service) ?? [];
      list.push(s);
      bySvc.set(s.service, list);
    }
    return Array.from(bySvc.entries()).map(([service, list]) => ({
      service,
      label: this.serviceLabels[service] ?? service,
      settings: list,
      configured: list.every((s) => s.configured),
    }));
  });

  constructor() {
    for (const s of this.settings()) {
      this.form.addControl(s.key, new FormControl<string>('', { nonNullable: true }));
    }
  }

  save(group: ServiceGroup): void {
    this.savingService.set(group.service);
    const values: Record<string, string> = {};
    for (const s of group.settings) {
      values[s.key] = this.form.controls[s.key]?.value ?? '';
    }
    // Mock save — a real app would PUT these to the API.
    console.log('Saving settings for', group.service, values);
    setTimeout(() => {
      this.settings.update((list) =>
        list.map((s) => (s.service === group.service ? { ...s, configured: true } : s)),
      );
      this.savingService.set('');
    }, 500);
  }
}
